                    else:
                        write(f"[*] Social media '{social_url}' not found for '{profile_name}'.")
                else:
                    write("[-] Invalid action for social_medias. Use 'add' or 'remove'.")
                    return
            else:
                value = parts[4]
                profile_data[field] = value
